import React from 'react';
import '../styles/Profile.css';

const ProfilePage = () => {
  const user = {
    name: "User Name",
    role: "UI/UX Designer & Web Developer",
    location: "Lekki, Lagos",
    bio: "Specializing in building clean, functional interfaces with React. Passionate about bridging the gap between 3D aesthetics and modern web performance.",
    skills: ["React", "Tailwind CSS", "UI/UX Design", "C++", "Vite"],
  };

  return (
    <div className="min-h-screen bg-slate-50 p-6 md:p-12 relative overflow-hidden">
      {/* Background Decorative Gradient (Similar to your previous UI) */}
      <div className="absolute top-[-10%] right-[-5%] w-[500px] h-[500px] bg-blue-100 rounded-full blur-[120px] opacity-50 z-0"></div>
      
      <div className="max-w-4xl mx-auto relative z-10">
        {/* Profile Header Card */}
        <div className="bg-white/80 backdrop-blur-md border border-slate-200 rounded-3xl p-8 shadow-sm">
          <div className="flex flex-col md:flex-row items-center gap-8">
            {/* Profile Image Placeholder */}
            <div className="w-32 h-32 bg-gradient-to-tr from-blue-500 to-indigo-600 rounded-2xl flex items-center justify-center text-white text-4xl font-bold shadow-lg">
              {user.name.charAt(0)}
            </div>

            <div className="flex-1 text-center md:text-left">
              <h1 className="text-3xl font-bold text-slate-900">{user.name}</h1>
              <p className="text-indigo-600 font-medium mb-4">{user.role}</p>
              <p className="text-slate-600 leading-relaxed max-w-2xl">
                {user.bio}
              </p>
            </div>
          </div>

          <hr className="my-8 border-slate-100" />

          {/* Details Grid */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div>
              <h3 className="text-sm font-semibold text-slate-400 uppercase tracking-wider">Location</h3>
              <p className="text-slate-700">{user.location}</p>
            </div>
            <div className="md:col-span-2">
              <h3 className="text-sm font-semibold text-slate-400 uppercase tracking-wider mb-2">Technical Stack</h3>
              <div className="flex flex-wrap gap-2">
                {user.skills.map((skill) => (
                  <span key={skill} className="px-3 py-1 bg-slate-100 text-slate-600 rounded-full text-sm font-medium border border-slate-200">
                    {skill}
                  </span>
                ))}
              </div>
            </div>
          </div>
        </div>

        {/* Action Buttons */}
        <div className="mt-8 flex gap-4 justify-center md:justify-start">
          <button className="px-8 py-3 bg-indigo-600 text-white rounded-xl font-semibold hover:bg-indigo-700 transition-all shadow-md active:scale-95">
            Edit Profile
          </button>
          <button className="px-8 py-3 bg-white text-slate-700 border border-slate-200 rounded-xl font-semibold hover:bg-slate-50 transition-all active:scale-95">
            View Projects
          </button>
        </div>
      </div>
    </div>
  );
};

export default ProfilePage;
